(game "Solid Indigo Tench"
    (players 2)
    (equipment
        (board (square 5))
    )
    (rules
        (start
            (place P1 (12))
        )
        (play
            (once_through (P2)
                (place
                    (destination (and empty (adjacent occupied)))
                )
            )
            (repeat (P1 P2)
                (place
                    (destination (and empty (adjacent occupied)))
                )
            )
            (repeat (P1 P1 P2)
                (place
                    (destination (and empty (adjacent occupied)))
                )
            )
        )
        (end

            (if
                (exists
                    (and
                        (pattern (3 3) (0 1 0 1 1 1 0 0 0))
                        (and center (occupied P1))
                    )
                )
                (mover win)
            )


            (if (exists (pattern (2 2) (2 2 2 2))) (opponent win))


            (if (full_board) (draw))
        )
    )
    (rendering
        (color P1 "indigo")
        (color P2 "goldenrod")
    )
)

